34	// RunWithConfigViaService dispatches a single agent invocation through the
35	// agent service. It takes a sealed ResolvedConfig (durable knobs) and an
36	// AgentRunRuntime (per-invocation plumbing/intent), and is the SD-024
37	// successor to the retired RunViaService/RunViaServiceWith entry points.
38	//
39	// The virtual and script harnesses route through a DDx-owned Runner path,
40	// not the upstream service. These are not "carve-outs pending migration" —
41	// they are different products from upstream's same-named stubs. DDx's
42	// virtual is a content-addressed record/replay dictionary keyed by
43	// PromptHash; upstream's is a unit-test stub where callers stuff
44	// virtual.response into Metadata. DDx's script reads a filesystem directive
45	// file; upstream does not model this at all.
46	func RunWithConfigViaService(ctx context.Context, workDir string, rcfg config.ResolvedConfig, runtime AgentRunRuntime) (*Result, error) {
47		if ctx == nil {
48			ctx = context.Background()
49		}
50	
51		harness := rcfg.Harness()
52		if harness == "" && rcfg.Provider() != "" {
53			harness = rcfg.Provider()
54		}
55	
56		if harness == "virtual" || harness == "script" {
57			sessionLogDir := runtime.SessionLogDirOverride
58			if sessionLogDir == "" {
59				sessionLogDir = rcfg.SessionLogDir()
60			}
61			cfg := Config{SessionLogDir: ResolveLogDir(workDir, "")}
62			r := NewRunner(cfg)
63			r.WorkDir = workDir
64			return r.runInternal(RunArgs{
65				Context:       ctx,
66				Harness:       rcfg.Harness(),
67				Prompt:        runtime.Prompt,
68				PromptFile:    runtime.PromptFile,
69				PromptSource:  runtime.PromptSource,
70				Correlation:   runtime.Correlation,
71				Model:         rcfg.Model(),
72				Provider:      rcfg.Provider(),
73				ModelRef:      rcfg.ModelRef(),
74				Effort:        rcfg.Effort(),
75				Timeout:       rcfg.Timeout(),
76				WallClock:     rcfg.WallClock(),
77				WorkDir:       runtime.WorkDir,
78				Permissions:   rcfg.Permissions(),
79				SessionLogDir: sessionLogDir,
80			})
81		}
82	
83		svc, err := NewServiceFromWorkDir(workDir)
84		if err != nil {
85			return nil, fmt.Errorf("agent: build service: %w", err)
86		}
87		return executeOnService(ctx, svc, workDir, rcfg, runtime)
88	}
