90	// executeOnService dispatches against a pre-built svc using the durable
91	// knobs from rcfg and per-invocation plumbing from runtime, then records
92	// one session-index row. It is the inlined replacement for the retired
93	// RunViaServiceWith helper and is shared with dispatchViaResolvedConfig.
94	func executeOnService(ctx context.Context, svc agentlib.DdxAgent, workDir string, rcfg config.ResolvedConfig, runtime AgentRunRuntime) (*Result, error) {
95		if svc == nil {
96			return nil, fmt.Errorf("agent: nil service")
97		}
98		if ctx == nil {
99			ctx = context.Background()
100		}
101	
102		promptText := runtime.Prompt
103		if runtime.PromptFile != "" {
104			data, err := readPromptFileBounded(runtime.PromptFile)
105			if err != nil {
106				return nil, fmt.Errorf("agent: read prompt file: %w", err)
107			}
108			promptText = string(data)
109		}
110		if promptText == "" {
111			return nil, fmt.Errorf("agent: prompt is required")
112		}
113	
114		wd := runtime.WorkDir
115		if wd == "" {
116			wd = workDir
117		}
118		if wd == "" {
119			wd, _ = os.Getwd()
120		}
121	
122		idle := rcfg.Timeout()
123		if idle <= 0 {
124			idle = time.Duration(DefaultTimeoutMS) * time.Millisecond
125		}
126		wall := rcfg.WallClock()
127		if wall <= 0 {
128			wall = time.Duration(DefaultWallClockMS) * time.Millisecond
129		}
130	
131		sessionLogDir := runtime.SessionLogDirOverride
132		if sessionLogDir == "" {
133			sessionLogDir = rcfg.SessionLogDir()
134		}
135		if sessionLogDir == "" {
136			sessionLogDir = ResolveLogDir(workDir, "")
137		}
138	
139		harness := runtime.HarnessOverride
140		if harness == "" {
141			harness = rcfg.Harness()
142		}
143		if harness == "" && rcfg.Provider() != "" {
144			harness = rcfg.Provider()
145		}
146	
147		model := runtime.ModelOverride
148		if model == "" {
149			model = rcfg.Model()
150		}
151	
152		permissions := runtime.PermissionsOverride
153		if permissions == "" {
154			permissions = rcfg.Permissions()
155		}
156	
157		providerTimeout := ResolveProviderRequestTimeout(workDir, rcfg.Provider(), model, rcfg.ProviderRequestTimeout())
158	
159		req := agentlib.ServiceExecuteRequest{
160			Prompt:          promptText,
161			Model:           model,
162			Provider:        rcfg.Provider(),
163			Harness:         harness,
164			ModelRef:        rcfg.ModelRef(),
165			Reasoning:       agentlib.Reasoning(rcfg.Effort()),
166			Permissions:     permissions,
167			WorkDir:         wd,
168			Timeout:         wall,
169			IdleTimeout:     idle,
170			ProviderTimeout: providerTimeout,
171			SessionLogDir:   sessionLogDir,
172			Metadata:        runtime.Correlation,
173			MinPower:        rcfg.MinPower(),
174			MaxPower:        rcfg.MaxPower(),
175		}
176	
177		cancelCtx, cancel := context.WithCancel(ctx)
178		defer cancel()
179	
180		start := time.Now().UTC()
181		events, err := svc.Execute(cancelCtx, req)
182		if err != nil {
183			return nil, fmt.Errorf("agent: execute: %w", err)
184		}
185	
186		final, toolCalls, routing, actualPower := drainServiceEvents(events)
187		finishedAt := time.Now().UTC()
188		elapsed := finishedAt.Sub(start)
189	
190		result := &Result{
191			Harness:    harness,
192			Model:      model,
193			DurationMS: int(elapsed.Milliseconds()),
194			ToolCalls:  toolCalls,
195		}
196		if routing != nil {
197			result.Provider = routing.Provider
198			if routing.Model != "" {
199				result.Model = routing.Model
200			}
201			if routing.Harness != "" {
202				result.Harness = routing.Harness
203			}
204		}
205		if actualPower > 0 {
206			result.ActualPower = actualPower
207		}
208		if final != nil {
209			// Normalized final text from the upstream harness (agent-32e8ff5e);
210			// reviewer verdict extraction now parses this instead of raw stream
211			// frames (ddx-7bc0c8d5).
212			result.Output = final.FinalText
213			if final.Usage != nil {
214				// v0.9.1: Usage fields became *int (nullable).
215				if final.Usage.InputTokens != nil {
216					result.InputTokens = *final.Usage.InputTokens
217				}
218				if final.Usage.OutputTokens != nil {
219					result.OutputTokens = *final.Usage.OutputTokens
220				}
221				if final.Usage.TotalTokens != nil {
222					result.Tokens = *final.Usage.TotalTokens
223				}
224			}
225			if final.CostUSD > 0 {
226				result.CostUSD = final.CostUSD
227			}
228			if final.RoutingActual != nil {
229				if result.Provider == "" {
230					result.Provider = final.RoutingActual.Provider
231				}
232				if final.RoutingActual.Model != "" {
233					result.Model = final.RoutingActual.Model
234				}
235			}
236			switch final.Status {
237			case "success", "":
238				// happy path
239			case "stalled":
240				result.ExitCode = 1
241				if final.Error != "" {
242					result.Error = "stalled: " + final.Error
243				} else {
244					result.Error = "stalled"
245				}
246			case "timed_out":
247				result.ExitCode = 1
248				result.Error = fmt.Sprintf("timeout after %v", wall.Round(time.Second))
249			case "cancelled":
250				result.ExitCode = 1
251				result.Error = "cancelled"
252			default:
253				result.ExitCode = 1
254				if final.Error != "" {
255					result.Error = final.Error
256				} else {
257					result.Error = final.Status
258				}
259			}
260			result.Error = appendProviderTimeoutHint(result.Error, providerTimeout)
261			if final.SessionLogPath != "" {
262				result.AgentSessionID = final.SessionLogPath
263			}
264		}
265		entry := SessionIndexEntryFromResult(workDir, SessionIndexInputs{
266			Harness:     harness,
267			Model:       model,
268			Provider:    rcfg.Provider(),
269			Effort:      rcfg.Effort(),
270			Correlation: runtime.Correlation,
271		}, result, start, finishedAt)
272		_ = AppendSessionIndex(ResolveLogDir(workDir, ""), entry, finishedAt)
273		return result, nil
274	}
