276	// CapabilitiesViaService returns HarnessCapabilities for the named harness by
277	// querying the service's ListHarnesses and (best-effort) the harness registry.
278	// It is the production replacement for Runner.Capabilities.
279	func CapabilitiesViaService(ctx context.Context, workDir, harnessName string) (*HarnessCapabilities, error) {
280		if ctx == nil {
281			ctx = context.Background()
282		}
283		svc, err := NewServiceFromWorkDir(workDir)
284		if err != nil {
285			return nil, fmt.Errorf("agent: build service: %w", err)
286		}
287		infos, err := svc.ListHarnesses(ctx)
288		if err != nil {
289			return nil, fmt.Errorf("agent: list harnesses: %w", err)
290		}
291		var info *agentlib.HarnessInfo
292		for i := range infos {
293			if infos[i].Name == harnessName {
294				info = &infos[i]
295				break
296			}
297		}
298		if info == nil {
299			return nil, fmt.Errorf("agent: unknown harness: %s", harnessName)
300		}
301	
302		// Pull binary and reasoning-level metadata from the local registry — the
303		// service does not expose these directly today.
304		registry := newHarnessRegistry()
305		harness, _ := registry.Get(harnessName)
306	
307		caps := &HarnessCapabilities{
308			Harness:             info.Name,
309			Available:           info.Available,
310			Binary:              harness.Binary,
311			Path:                info.Path,
312			Surface:             harness.Surface,
313			CostClass:           info.CostClass,
314			IsLocal:             info.IsLocal,
315			ExactPinSupport:     info.ExactPinSupport,
316			SupportsEffort:      len(info.SupportedReasoning) > 0 || harness.EffortFlag != "",
317			SupportsPermissions: len(info.SupportedPermissions) > 0 || len(harness.PermissionArgs) > 0,
318		}
319		if len(info.SupportedReasoning) > 0 {
320			caps.ReasoningLevels = append([]string{}, info.SupportedReasoning...)
321		} else if len(harness.ReasoningLevels) > 0 {
322			caps.ReasoningLevels = append([]string{}, harness.ReasoningLevels...)
323		}
324	
325		if harness.DefaultModel != "" {
326			caps.Model = harness.DefaultModel
327			caps.Models = []string{harness.DefaultModel}
328		}
329	
330		// Profile mappings come from the local model catalog because the service
331		// does not surface a per-tier resolution endpoint today.
332		if harness.Surface != "" {
333			cat := BuiltinCatalog
334			for _, profile := range []string{"cheap", "fast", "smart"} {
335				if m, ok := cat.Resolve(profile, harness.Surface); ok {
336					if caps.ProfileMappings == nil {
337						caps.ProfileMappings = make(map[string]string)
338					}
339					caps.ProfileMappings[profile] = m
340				}
341			}
342		}
343		return caps, nil
344	}
