383	// ValidateForExecuteLoopViaService is the production replacement for
384	// Runner.ValidateForExecuteLoop. When harness is empty it is a no-op (routing
385	// will pick at claim time). When harness is specified it confirms the harness
386	// exists in the service registry and (when model is set) attempts a
387	// ResolveRoute pre-flight.
388	func ValidateForExecuteLoopViaService(ctx context.Context, workDir, harnessName, model, provider, modelRef string) error {
389		if harnessName == "" {
390			return nil
391		}
392		if ctx == nil {
393			ctx = context.Background()
394		}
395		svc, err := NewServiceFromWorkDir(workDir)
396		if err != nil {
397			return fmt.Errorf("agent: build service: %w", err)
398		}
399		infos, err := svc.ListHarnesses(ctx)
400		if err != nil {
401			return fmt.Errorf("agent: list harnesses: %w", err)
402		}
403		found := false
404		for _, info := range infos {
405			if info.Name == harnessName {
406				found = true
407				if !info.Available {
408					return fmt.Errorf("agent: harness %s not available", harnessName)
409				}
410				break
411			}
412		}
413		if !found {
414			return fmt.Errorf("agent: unknown harness: %s", harnessName)
415		}
416	
417		// Pre-flight orphan-model check via ResolveRoute. Only meaningful when a
418		// model is provided and provider/model-ref are not set.
419		if model != "" && provider == "" && modelRef == "" && harnessName == "agent" {
420			if _, err := svc.ResolveRoute(ctx, agentlib.RouteRequest{
421				Model:    model,
422				Harness:  harnessName,
423				ModelRef: modelRef,
424				Provider: provider,
425			}); err != nil {
426				return fmt.Errorf("agent: model %q is not routable: %w", model, err)
427			}
428		}
429		return nil
430	}
