1109	func ResolveGoverningRefs(root string, b *bead.Bead) []executeBeadGoverningRef {
1110		specIDRaw, _ := b.Extra["spec-id"].(string)
1111		specIDRaw = strings.TrimSpace(specIDRaw)
1112		if specIDRaw == "" {
1113			return nil
1114		}
1115	
1116		// spec-id may be a comma-separated list of IDs or paths.
1117		ids := strings.Split(specIDRaw, ",")
1118		graph, _ := docgraph.BuildGraphWithConfig(root)
1119	
1120		var refs []executeBeadGoverningRef
1121		for _, specID := range ids {
1122			specID = strings.TrimSpace(specID)
1123			if specID == "" {
1124				continue
1125			}
1126			if graph != nil {
1127				if doc, ok := graph.Documents[specID]; ok && doc != nil {
1128					refs = append(refs, executeBeadGoverningRef{
1129						ID:    doc.ID,
1130						Path:  filepath.ToSlash(strings.TrimPrefix(strings.TrimPrefix(doc.Path, root), string(filepath.Separator))),
1131						Title: doc.Title,
1132					})
1133					continue
1134				}
1135			}
1136			candidate := filepath.Clean(filepath.Join(root, filepath.FromSlash(specID)))
1137			relCandidate, relErr := filepath.Rel(root, candidate)
1138			if relErr != nil || strings.HasPrefix(relCandidate, ".."+string(filepath.Separator)) || relCandidate == ".." {
1139				continue
1140			}
1141			info, statErr := os.Stat(candidate)
1142			if statErr != nil || info.IsDir() {
1143				continue
1144			}
1145			refs = append(refs, executeBeadGoverningRef{
1146				ID:   specID,
1147				Path: filepath.ToSlash(relCandidate),
1148			})
1149		}

