package config

// AgentPassthrough carries the resolved harness/provider/model routing
// constraints from the operator invocation through to the upstream agent
// service as a single, opaque unit.
//
// DDx treats the string values as opaque after resolution: they are not
// validated against harness registries, model catalogs, or endpoint
// policies inside DDx. The agent service is the sole authority on
// whether the combination is valid and routable. This preserves the
// FEAT-006 invariant that DDx does not re-implement DDx-side routing
// decisions.
//
// Usage: obtain via ResolvedConfig.Passthrough() and pass to
// agent.executeOnService. Do not read Harness/Provider/Model from this
// struct for queue selection, retry policy, endpoint policy, catalog
// threshold evaluation, or config defaulting — those are routing
// concerns that belong to the upstream agent service.
type AgentPassthrough struct {
	// Harness is the harness name resolved from CLI --harness or the
	// project's agent.harness config key. Empty means "let the agent
	// service choose".
	Harness string
	// Provider is the provider name from CLI --provider. Empty means "let
	// the agent service choose". Unlike Harness, Provider has no durable
	// config-file home and is always CLI-only.
	Provider string
	// Model is the model name resolved from CLI --model or the project's
	// agent.model config key. Empty means "let the agent service choose".
	Model string
}

