package agent

// passthrough_envelope_test.go covers the FEAT-006 / ddx-20047dd5
// passthrough-envelope acceptance criteria:
//
//   AC3: Retry MinPower escalation keeps the passthrough envelope
//        unchanged and preserves MaxPower.
//   AC6: Invalid passthrough values are not prevalidated by DDx;
//        they are forwarded to the agent service and surface from
//        the service response/error.
//   AC7: Passthrough-plus-power conflicts produce the typed stop
//        statuses blocked_by_passthrough_constraint or
//        agent_power_unsatisfied rather than mutating pins or looping.

import (
	"context"
	"encoding/json"
	"fmt"
	"testing"
	"time"

	agentlib "github.com/DocumentDrivenDX/agent"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// --- AC3: passthrough envelope is invariant under MinPower escalation ---

// TestPassthroughEnvelope_InvariantUnderPowerEscalation verifies that
// escalating MinPower (simulating a retry with a higher power floor) does
// not mutate the harness/provider/model passthrough pins and does not
// widen MaxPower. The passthrough envelope must be identical before and
// after the power change.
func TestPassthroughEnvelope_InvariantUnderPowerEscalation(t *testing.T) {
	baseOverrides := config.CLIOverrides{
		Harness:  "claude",
		Provider: "anthropic",
		Model:    "claude-sonnet",
		MinPower: 10,
		MaxPower: 80,
	}
	// Simulate MinPower escalation by creating overrides with a higher floor.
	escalatedOverrides := baseOverrides
	escalatedOverrides.MinPower = 50

	cfg := config.DefaultNewConfig()
	base := cfg.Resolve(baseOverrides)
	escalated := cfg.Resolve(escalatedOverrides)

	// Passthrough must be identical regardless of the MinPower change.
	assert.Equal(t, base.Passthrough().Harness, escalated.Passthrough().Harness,
		"Harness must not change when MinPower is escalated")
	assert.Equal(t, base.Passthrough().Provider, escalated.Passthrough().Provider,
		"Provider must not change when MinPower is escalated")
	assert.Equal(t, base.Passthrough().Model, escalated.Passthrough().Model,
		"Model must not change when MinPower is escalated")

	// MaxPower must be preserved — power escalation raises the floor, not
	// the ceiling. DDx must not widen MaxPower.
	assert.Equal(t, base.MaxPower(), escalated.MaxPower(),
		"MaxPower must not change during MinPower escalation")
}

// TestPassthroughEnvelope_EmptyIsPreserved verifies that a zero-value
