// passthroughTestService is a minimal agentlib.DdxAgent stub that records
// whether Execute and ListHarnesses were called and returns configurable
// responses. Used to verify that executeOnService forwards the passthrough
// to Execute without calling ListHarnesses for validation.
type passthroughTestService struct {
	executeErr          error
	executeReq          agentlib.ServiceExecuteRequest
	executeCalled       bool
	listHarnessesCalled bool
}

func (s *passthroughTestService) Execute(ctx context.Context, req agentlib.ServiceExecuteRequest) (<-chan agentlib.ServiceEvent, error) {
	s.executeCalled = true
	s.executeReq = req
	if s.executeErr != nil {
		return nil, s.executeErr
	}
	// Return a minimal success stream.
	events := make(chan agentlib.ServiceEvent, 2)
	payload, _ := json.Marshal(map[string]any{
		"status":     "success",
		"exit_code":  0,
		"final_text": "ok",
	})
	events <- agentlib.ServiceEvent{
		Type: "final",
		Time: time.Now(),
		Data: payload,
	}
	close(events)
	return events, nil
}

