// TestExecuteOnService_InvalidPassthroughNotPrevalidated verifies AC6:
// executeOnService forwards harness/provider/model to svc.Execute without
// calling ListHarnesses for validation. An invalid harness string must reach
// the service as-is; the error comes from Execute, not from a DDx-side
// harness availability check.
func TestExecuteOnService_InvalidPassthroughNotPrevalidated(t *testing.T) {
	const invalidHarness = "!invalid-harness-ddx-must-not-validate!"
	expectedErr := fmt.Errorf("agent: unknown harness: %s", invalidHarness)

	svc := &passthroughTestService{executeErr: expectedErr}

	cfg := config.NewTestConfigForBead(config.TestBeadConfigOpts{
		Harness: invalidHarness,
	})
	rcfg := cfg.Resolve(config.TestBeadOverrides(config.TestBeadConfigOpts{
		Harness: invalidHarness,
	}))

	_, err := executeOnService(context.Background(), svc, t.TempDir(), rcfg, AgentRunRuntime{
		Prompt: "test prompt",
	})

	// The error must surface from Execute, not from a DDx-side harness check.
	require.Error(t, err, "executeOnService must propagate the service error")
	assert.Contains(t, err.Error(), invalidHarness,
		"error must name the invalid harness (from service, not DDx)")
	assert.True(t, svc.executeCalled,
		"executeOnService must call svc.Execute even for an invalid harness value")
	assert.False(t, svc.listHarnessesCalled,
		"executeOnService must NOT call ListHarnesses to validate the passthrough harness")
}

// TestExecuteOnService_PassthroughReachesServiceRequest verifies that
// harness, provider, and model from the passthrough envelope reach the
// ServiceExecuteRequest exactly — no fallback, no substitution.
func TestExecuteOnService_PassthroughReachesServiceRequest(t *testing.T) {
	svc := &passthroughTestService{}

	cfg := config.NewTestConfigForBead(config.TestBeadConfigOpts{
		Harness: "my-harness",
		Model:   "my-model",
	})
	rcfg := cfg.Resolve(config.CLIOverrides{
		Provider: "my-provider",
	})

	_, err := executeOnService(context.Background(), svc, t.TempDir(), rcfg, AgentRunRuntime{
		Prompt: "test prompt",
	})
	require.NoError(t, err)

	assert.Equal(t, "my-harness", svc.executeReq.Harness,
		"Harness must come from the passthrough envelope")
	assert.Equal(t, "my-provider", svc.executeReq.Provider,
		"Provider must come from the passthrough envelope")
	assert.Equal(t, "my-model", svc.executeReq.Model,
		"Model must come from the passthrough envelope")
}

// --- AC7: passthrough-plus-power conflicts stop with typed failure modes ---

// TestClassifyFailureMode_BlockedByPassthroughConstraint verifies that
// error messages indicating a passthrough constraint conflict (e.g. harness
// pin + incompatible power bounds) map to FailureModeBlockedByPassthroughConstraint.
func TestClassifyFailureMode_BlockedByPassthroughConstraint(t *testing.T) {
	cases := []struct {
		errMsg string
	}{
		{"passthrough constraint unsatisfiable: max_power=60 is less than min_power=80"},
		{"passthrough constraint: harness agent cannot satisfy power bounds"},
		{"max_power is less than min_power: 60 < 80"},
		{"max_power exceeds min_power — routing cannot proceed"},
		{"harness cannot satisfy power constraint: claude requires power >= 70"},
		{"harness pin incompatible with power bounds: requested power 90 unavailable"},
		{"model pin incompatible with power bounds"},
		{"provider pin incompatible with power bounds"},
	}
	for _, tc := range cases {
		t.Run(tc.errMsg, func(t *testing.T) {
			mode := ClassifyFailureMode(ExecuteBeadOutcomeTaskFailed, 1, tc.errMsg)
			assert.Equal(t, FailureModeBlockedByPassthroughConstraint, mode,
				"error %q must map to blocked_by_passthrough_constraint", tc.errMsg)
		})
	}
}

// TestClassifyFailureMode_AgentPowerUnsatisfied verifies that error messages
// indicating the agent service cannot find a model meeting the power bound
// map to FailureModeAgentPowerUnsatisfied.
func TestClassifyFailureMode_AgentPowerUnsatisfied(t *testing.T) {
	cases := []struct {
		errMsg string
	}{
		{"agent power unsatisfied: no model with power >= 90 available"},
		{"no model meets min_power=95 constraint"},
		{"no model with power >= 80"},
		{"minimum power not achievable: best available power is 70"},
		{"min_power constraint cannot be satisfied: power ceiling is 65"},
	}
	for _, tc := range cases {
		t.Run(tc.errMsg, func(t *testing.T) {
			mode := ClassifyFailureMode(ExecuteBeadOutcomeTaskFailed, 1, tc.errMsg)
			assert.Equal(t, FailureModeAgentPowerUnsatisfied, mode,
				"error %q must map to agent_power_unsatisfied", tc.errMsg)
		})
	}
}

// TestClassifyFailureMode_PassthroughModesDistinctFromGenericFailure verifies
// that the passthrough-specific failure modes do not absorb generic errors:
// a normal auth error or timeout must not map to the new constants.
func TestClassifyFailureMode_PassthroughModesDistinctFromGenericFailure(t *testing.T) {
	cases := []struct {
		errMsg   string
		notWant  string
	}{
		{"401 unauthorized", FailureModeBlockedByPassthroughConstraint},
		{"timeout after 30s", FailureModeAgentPowerUnsatisfied},
		{"no viable provider", FailureModeBlockedByPassthroughConstraint},
		{"context length exceeded", FailureModeAgentPowerUnsatisfied},
	}
	for _, tc := range cases {
		t.Run(tc.errMsg, func(t *testing.T) {
			mode := ClassifyFailureMode(ExecuteBeadOutcomeTaskFailed, 1, tc.errMsg)
			assert.NotEqual(t, tc.notWant, mode,
				"generic error %q must not map to passthrough-specific failure mode %s",
				tc.errMsg, tc.notWant)
		})
	}
}

